import{_ as a,o as s,c as t,a2 as i}from"./chunks/framework.CHSDihme.js";const o="/claude-code-token-free/assets/01-create-app-entry.Dpzfs5LM.png",r="/claude-code-token-free/assets/02-name-bot.B_5f4ipU.png",p="/claude-code-token-free/assets/03-dev-console.D9d0U7Bf.png",l="/claude-code-token-free/assets/04-menu-enter.C0-jvWQk.png",n="/claude-code-token-free/assets/05-menu-projects.DqXvCSgY.png",c="/claude-code-token-free/assets/06-menu-new.BXrxzIC7.png",d="/claude-code-token-free/assets/07-menu-clear.CFfustEW.png",h="/claude-code-token-free/assets/08-menu-save.vFjESm1j.png",u="/claude-code-token-free/assets/09-publish-version.DoXjqk-w.png",k="/claude-code-token-free/assets/10-fill-app-credentials.pMk1iS8U.png",g="/claude-code-token-free/assets/11-generate-pairing-code.C6VKB8Eg.png",m="/claude-code-token-free/assets/12-pairing-code-detail.DE_pMQZ5.png",f="/claude-code-token-free/assets/13-send-code-in-feishu.Bqrd2tQH.png",_="/claude-code-token-free/assets/14-pair-success.DBqUIWYA.png",b="/claude-code-token-free/assets/15-pair-done.mrRZaBaK.png",v=JSON.parse('{"title":"飞书接入","description":"","frontmatter":{},"headers":[],"relativePath":"im/feishu.md","filePath":"im/feishu.md","lastUpdated":1780649039000}'),q={name:"im/feishu.md"};function F(x,e,C,E,P,y){return s(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="飞书接入" tabindex="-1">飞书接入 <a class="header-anchor" href="#飞书接入" aria-label="Permalink to &quot;飞书接入&quot;">​</a></h1><blockquote><p>飞书 Adapter 的接入教程。官方已经提供了<strong>预配好权限的模板机器人</strong>，跟着下面几步点一点就能完成接入。</p></blockquote><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><p>飞书方案适合在中国区环境下通过企业自建应用私聊 Claude Code。当前实现只处理 <code>p2p</code> 私聊，不处理群聊。</p><p>实现入口：<code>adapters/feishu/index.ts</code></p><h2 id="1-一键创建飞书机器人" tabindex="-1">1. 一键创建飞书机器人 <a class="header-anchor" href="#1-一键创建飞书机器人" aria-label="Permalink to &quot;1. 一键创建飞书机器人&quot;">​</a></h2><p>直接打开下面的链接创建机器人——这是官方为 OpenClaw 提前配好所有权限（消息、事件、卡片回调等）的模板，省去手动配 scope 和事件订阅：</p><p>👉 <a href="https://open.feishu.cn/page/openclaw?form=multiAgent" target="_blank" rel="noreferrer">立即创建飞书机器人</a></p><p><img src="'+o+'" alt="一键创建入口"></p><p>随便给你自己的机器人取一个名字，点击创建：</p><p><img src="'+r+'" alt="取名并创建"></p><p>创建成功后，把 <strong>App ID</strong> 和 <strong>App Secret</strong> 保存下来，接着去配置机器人菜单。</p><h2 id="2-配置自定义菜单projects-new-clear" tabindex="-1">2. 配置自定义菜单（/projects /new /clear） <a class="header-anchor" href="#2-配置自定义菜单projects-new-clear" aria-label="Permalink to &quot;2. 配置自定义菜单（/projects /new /clear）&quot;">​</a></h2><p>进入<a href="https://open.feishu.cn/app?lang=zh-CN" target="_blank" rel="noreferrer">飞书开发者后台</a>，选择刚创建的机器人，进入机器人配置页：</p><p><img src="'+p+'" alt="开发者后台"></p><p>进入「机器人菜单」开始配置：</p><p><img src="'+l+'" alt="进入菜单配置"></p><p>依次添加 3 个命令：</p><p><strong>/projects</strong> — 切换最近使用的项目</p><p><img src="'+n+'" alt="菜单 /projects"></p><p><strong>/new</strong> — 开启新对话</p><p><img src="'+c+'" alt="菜单 /new"></p><p><strong>/clear</strong> — 清空上下文</p><p><img src="'+d+'" alt="菜单 /clear"></p><p>三个都配好后点击保存：</p><p><img src="'+h+'" alt="保存菜单"></p><p>最后点击「创建新版本并发布」让菜单生效：</p><p><img src="'+u+'" alt="创建版本并发布"></p><p><strong>命令作用说明：</strong></p><ul><li><code>/projects</code>：列出最近使用的项目，支持切换当前会话绑定的目录</li><li><code>/new</code>：开启新对话</li><li><code>/clear</code>：清空当前会话上下文</li></ul><h2 id="3-在-claude-code-token-free-桌面端填写" tabindex="-1">3. 在 Claude Code Token Free 桌面端填写 <a class="header-anchor" href="#3-在-claude-code-token-free-桌面端填写" aria-label="Permalink to &quot;3. 在 Claude Code Token Free 桌面端填写&quot;">​</a></h2><h3 id="31-填写-app-id--app-secret" tabindex="-1">3.1 填写 App ID / App Secret <a class="header-anchor" href="#31-填写-app-id--app-secret" aria-label="Permalink to &quot;3.1 填写 App ID / App Secret&quot;">​</a></h3><p>打开桌面端 <code>设置 → IM 接入 → 飞书</code>，把前面拿到的两把钥匙填进去：</p><p><img src="'+k+'" alt="填写 App ID / App Secret"></p><h3 id="32-生成配对码" tabindex="-1">3.2 生成配对码 <a class="header-anchor" href="#32-生成配对码" aria-label="Permalink to &quot;3.2 生成配对码&quot;">​</a></h3><p>点击「生成配对码」按钮，得到 6 位码：</p><p><img src="'+g+'" alt="生成配对码"></p><p><img src="'+m+'" alt="配对码详情"></p><p><strong>记得点保存！！</strong></p><h2 id="4-飞书机器人与桌面端配对" tabindex="-1">4. 飞书机器人与桌面端配对 <a class="header-anchor" href="#4-飞书机器人与桌面端配对" aria-label="Permalink to &quot;4. 飞书机器人与桌面端配对&quot;">​</a></h2><p>随便给刚才创建的机器人发送一条消息，按提示把上一步的 6 位配对码发给它：</p><p><img src="'+f+'" alt="在飞书里发配对码"></p><p>看到配对成功提示后，就可以用飞书在手机上远程驱动桌面端 Claude Code Token Free 了：</p><p><img src="'+_+'" alt="配对成功"></p><p><img src="'+b+`" alt="可以开始对话"></p><h2 id="支持的命令" tabindex="-1">支持的命令 <a class="header-anchor" href="#支持的命令" aria-label="Permalink to &quot;支持的命令&quot;">​</a></h2><p>除菜单按钮外，飞书 adapter 还支持文本命令和中文别名：</p><ul><li><code>/help</code> 或 <code>帮助</code></li><li><code>/status</code> 或 <code>状态</code></li><li><code>/clear</code> 或 <code>清空</code></li><li><code>/projects</code> 或 <code>项目列表</code></li><li><code>/new</code> 或 <code>新会话</code></li><li><code>/stop</code> 或 <code>停止</code></li></ul><h2 id="权限审批" tabindex="-1">权限审批 <a class="header-anchor" href="#权限审批" aria-label="Permalink to &quot;权限审批&quot;">​</a></h2><p>当 Claude 请求敏感权限时，adapter 会在飞书里发送交互卡片，点击「允许 / 拒绝」即可把结果回传给桌面端。</p><h2 id="返回消息的表现" tabindex="-1">返回消息的表现 <a class="header-anchor" href="#返回消息的表现" aria-label="Permalink to &quot;返回消息的表现&quot;">​</a></h2><ul><li>普通文本通过 <code>post</code> 消息发送</li><li>权限审批通过卡片发送</li><li>流式内容优先 patch 同一条消息</li><li>完成后按 30000 字左右分片</li></ul><h2 id="启动-adapter" tabindex="-1">启动 adapter <a class="header-anchor" href="#启动-adapter" aria-label="Permalink to &quot;启动 adapter&quot;">​</a></h2><p>桌面端会自动把 adapter 作为 sidecar 拉起。如果你在本地开发，需要手动启动：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> adapters</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feishu</span></span></code></pre></div><h2 id="环境变量覆盖可选" tabindex="-1">环境变量覆盖（可选） <a class="header-anchor" href="#环境变量覆盖可选" aria-label="Permalink to &quot;环境变量覆盖（可选）&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> FEISHU_APP_ID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;cli_xxx&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> FEISHU_APP_SECRET</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;xxx&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ADAPTER_SERVER_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ws://127.0.0.1:3456&quot;</span></span></code></pre></div><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="一键创建后的机器人权限够用吗" tabindex="-1">一键创建后的机器人权限够用吗？ <a class="header-anchor" href="#一键创建后的机器人权限够用吗" aria-label="Permalink to &quot;一键创建后的机器人权限够用吗？&quot;">​</a></h3><p>OpenClaw 官方模板已预配 <code>im:message</code>、<code>im:message:send_as_bot</code>、<code>im:resource</code>、<code>im.message.receive_v1</code>、<code>card.action.trigger</code> 等所有所需权限，<strong>不需要再手动去配 scope 或事件订阅</strong>。</p><h3 id="收不到消息" tabindex="-1">收不到消息 <a class="header-anchor" href="#收不到消息" aria-label="Permalink to &quot;收不到消息&quot;">​</a></h3><p>优先检查：</p><ul><li>机器人是否已发布（菜单改完需要「创建新版本并发布」）</li><li>是否真的是和 bot 的私聊，而不是群聊</li></ul><h3 id="权限按钮点了没反应" tabindex="-1">权限按钮点了没反应 <a class="header-anchor" href="#权限按钮点了没反应" aria-label="Permalink to &quot;权限按钮点了没反应&quot;">​</a></h3><p>通常是 <code>card.action.trigger</code> 没生效，重新在开发者后台发布一次版本即可。</p><h3 id="一直提示未授权" tabindex="-1">一直提示未授权 <a class="header-anchor" href="#一直提示未授权" aria-label="Permalink to &quot;一直提示未授权&quot;">​</a></h3><ul><li>配对码是否仍在 60 分钟有效期内</li><li>发的是不是桌面端当前这一枚（重新生成后旧的立即失效）</li><li><code>feishu.pairedUsers</code> 里是否已经写入当前 <code>open_id</code></li></ul><h3 id="会话没恢复" tabindex="-1">会话没恢复 <a class="header-anchor" href="#会话没恢复" aria-label="Permalink to &quot;会话没恢复&quot;">​</a></h3><p>检查 <code>~/.claude/adapter-sessions.json</code> 是否能正常写入，以及 Desktop server 里的 session 是否仍存在。</p><h2 id="源码入口" tabindex="-1">源码入口 <a class="header-anchor" href="#源码入口" aria-label="Permalink to &quot;源码入口&quot;">​</a></h2><ul><li><code>adapters/feishu/index.ts</code></li><li><code>adapters/common/pairing.ts</code></li><li><code>adapters/common/session-store.ts</code></li><li><code>adapters/common/ws-bridge.ts</code></li><li><code>adapters/common/http-client.ts</code></li></ul>`,71)])])}const D=a(q,[["render",F]]);export{v as __pageData,D as default};
